class Solution {
    public List<List<Integer>> pacificAtlantic(int[][] heights) {
        int m = heights.length, n = heights[0].length;
        boolean[][] pac = new boolean[m][n];
        boolean[][] atl = new boolean[m][n];
        Queue<int[]> qp = new LinkedList<>(), qa = new LinkedList<>();
        for (int i = 0; i < m; i++) {
            qp.add(new int[]{i, 0});
            qa.add(new int[]{i, n-1});
            pac[i][0] = true;
            atl[i][n-1] = true;
        }
        for (int j = 0; j < n; j++) {
            qp.add(new int[]{0, j});
            qa.add(new int[]{m-1, j});
            pac[0][j] = true;
            atl[m-1][j] = true;
        }
        bfs(heights, pac, qp);
        bfs(heights, atl, qa);
        List<List<Integer>> ans = new ArrayList<>();
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (pac[i][j] && atl[i][j]) ans.add(Arrays.asList(i, j));
            }
        }
        return ans;
    }
    private void bfs(int[][] heights, boolean[][] visited, Queue<int[]> q) {
        int m = heights.length, n = heights[0].length;
        int[][] dirs = {{1,0},{-1,0},{0,1},{0,-1}};
        while (!q.isEmpty()) {
            int[] curr = q.poll();
            for (int[] d : dirs) {
                int ni = curr[0] + d[0], nj = curr[1] + d[1];
                if (ni >= 0 && ni < m && nj >= 0 && nj < n && !visited[ni][nj] && heights[ni][nj] >= heights[curr[0]][curr[1]]) {
                    visited[ni][nj] = true;
                    q.add(new int[]{ni, nj});
                }
            }
        }
    }
}
